```csharp
using System;
using System.Data;
using System.Data.SQLite;

namespace MyApp
{
    class Program
    {
        static void Main(string[] args)
        {
            string connectionString = "Data Source=E:\\code\\BEWG\\ElectricalWpfApp\\Data\\eletrical.db;Version=3;"; // 指定SQLite数据文件路径和版本

            using (SQLiteConnection connection = new SQLiteConnection(connectionString))
            {
                connection.Open(); // 打开数据库连接

                string sql = "SELECT * FROM myTable"; // 定义查询语句

                using (SQLiteDataAdapter adapter = new SQLiteDataAdapter(sql, connection))
                {
                    DataSet dataset = new DataSet(); // 创建数据集对象

                    adapter.Fill(dataset, "myTable"); // 将查询结果填充到数据集中

                    foreach (DataRow row in dataset.Tables["myTable"].Rows) // 遍历数据集中的行数据
                    {
                        Console.WriteLine("ID: {0}, Name: {1}, Age: {2}", row["ID"], row["Name"], row["Age"]);
                    }
                }

                connection.Close(); // 关闭数据库连接
            }

            Console.ReadLine();
        }
    }
}
```

