```csharp
using System;
using System.Collections.Generic;
using System.Data;
using System.Data.SQLite;

namespace MyApp
{
    class Person
    {
        public int ID { get; set; }
        public string Name { get; set; }
        public int Age { get; set; }
    }

    class Program
    {
        static void Main(string[] args)
        {
            string connectionString = "Data Source=E:\\code\\BEWG\\ElectricalWpfApp\\Data\\eletrical.db;Version=3;"; // 指定SQLite数据文件路径和版本

            using (SQLiteConnection connection = new SQLiteConnection(connectionString))
            {
                connection.Open(); // 打开数据库连接

                string sql = "SELECT ID, Name, Age FROM myTable"; // 定义查询语句

                using (SQLiteDataAdapter adapter = new SQLiteDataAdapter(sql, connection))
                {
                    DataSet dataset = new DataSet(); // 创建数据集对象

                    adapter.Fill(dataset, "myTable"); // 将查询结果填充到数据集中

                    List<Person> persons = new List<Person>(); // 创建Person对象列表

                    foreach (DataRow row in dataset.Tables["myTable"].Rows) // 遍历数据集中的行数据
                    {
                        Person person = new Person(); // 创建新的Person对象

                        person.ID = Convert.ToInt32(row["ID"]); // 解构查询结果到Person对象中
                        person.Name = Convert.ToString(row["Name"]);
                        person.Age = Convert.ToInt32(row["Age"]);

                        persons.Add(person); // 将Person对象添加到列表中
                    }

                    foreach (Person person in persons) // 遍历Person对象列表
                    {
                        Console.WriteLine("ID: {0}, Name: {1}, Age: {2}", person.ID, person.Name, person.Age);
                    }
                }

                connection.Close(); // 关闭数据库连接
            }

            Console.ReadLine();
        }
    }
}
```

在这个示例中，我们首先创建了一个Person类，它具有ID、Name和Age属性。然后，我们创建了一个SQLiteConnection对象，打开了数据库连接，并定义了查询语句。在查询语句中，我们指定了要查询的列名称（ID、Name和Age）。

接着，我们创建了一个SQLiteDataAdapter对象，并使用查询语句和连接对象初始化它。然后，我们使用DataAdapter的Fill方法将查询结果填充到一个DataSet对象中，并遍历它的行数据。在每一行数据中，我们创建一个新的Person对象，并使用Convert类中的方法将查询结果解构到它的属性中。最后，我们将Person对象添加到一个列表中。

在遍历完Person对象列表后，我们将每个Person对象的ID、Name和Age属性输出到控制台上。

